INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-f29af906-moex-00478', 'elementary-f29af906', 'elementary-f29af906-moex-112-34c7f7f6', 'sub-elementary-f29af906-02', NULL, 'single_choice', '「要使這個社會治安趨於良好，最重要的是勸導那些不法之徒，能夠□□□□。」 下列成語，何者適合填入空格內？', '["明辨是非", "不念舊惡", "遷善改過", "除舊布新 洗心革面"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00479', 'elementary-f29af906', 'elementary-f29af906-moex-112-34c7f7f6', 'sub-elementary-f29af906-02', NULL, 'single_choice', '下列文句「」中的成語，運用正確的是：', '["父親教導我們默默行善，以免有「沽名釣譽」之嫌", "警方鎖定的陳姓嫌犯「危言危行」，民眾十分恐慌", "具創造力的人常「見異思遷」，能不斷開發新產品", "張局長高瞻遠矚，總是能「見微知著」，超前部署 比賽選手個個舌粲蓮花，「信口開河」的進行演說"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00480', 'elementary-f29af906', 'elementary-f29af906-moex-112-34c7f7f6', 'sub-elementary-f29af906-02', NULL, 'single_choice', '「天地間有些東西沒有主人，例如自然美景。既然無主，我們可以盡情享有，大自然不加限 制。審美的能力是先天稟賦加後天修養，我們之所得無人可以侵占。『失去那不能擁有的， 得到那不能奪去的。』這是我們這等人擁有的永恆。千江有水千江月，面對天地之美，我們 的『擁有』並未使別人『失去』。」 下列選項，何者符合本文所說是屬於「並未使別人失去」的「擁有」，且「不能奪去的」？', '["超凡的審美能力", "永恆不朽的人生", "壯麗的江河山川", "寧靜皎潔的明月 珍愛的親密戀人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00481', 'elementary-f29af906', 'elementary-f29af906-moex-112-34c7f7f6', 'sub-elementary-f29af906-02', NULL, 'single_choice', '「楷書是字體中最整齊、最嚴謹的形式，唐人在書法上最大成就當屬『楷法』的創立，『法』 是法則、規律，從此以後，中國文字不再演化新的字體。唐以前的楷書是在追求一種法則下 進展的，三國時代的楷書仍帶有行書和隸書的筆勢，南朝楷書更加工整，但行書意味仍然濃 厚。北朝的魏碑體式多樣化，卻尚未尋找出它的規律性，隋代混同南北，成為唐楷的先驅。」 根據上文，下列選項正確的是：', '["唐人書法最大的特色是有書寫法則可以依循", "楷書的整齊嚴謹使它不得帶有行書隸書筆勢", "三國時代流行行書和隸書且沒有成熟的楷書", "南北朝楷書找到書寫規律性故表現趨勢一致 隋代能成為唐楷先驅是因其承襲南北朝發展"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00482', 'elementary-f29af906', 'elementary-f29af906-moex-112-34c7f7f6', 'sub-elementary-f29af906-02', NULL, 'single_choice', '「日子就這樣過去，消磨在管山管水裡。並不固執要去做什麼事，然而想來也沒什麼大後悔。 晚上入睡前，閉目感受周遭的寧靜，我總是心懷感激。大自然如此渺漠，卻又如此可親，和 我息息相關；我無法也不願割離。在黑暗中，我彷彿聽到了宇宙生命的呼吸和訓諭。我凝神 諦聽。時間緩緩流過。」 根據上文，下列選項符合文意的是：', '["抒發時光易逝的心中感慨", "顯露對於宇宙浩瀚的迷茫", "敘寫山居歲月的恬淡安然", "呈現離群索居的寂寞孤獨 表達對自然的敬畏與戀慕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00483', 'elementary-f29af906', 'elementary-f29af906-moex-112-34c7f7f6', 'sub-elementary-f29af906-02', NULL, 'single_choice', '有位法國哲人為人道主義下定義：「一個人於河中快淹死，一百個人跳下河中相救，這一百 個人也許會因而淹死，而仍救不上那個人來。以一百比一，是件不理智的行動，我們把這種 行動叫做人道主義。因為救的不是那個『一』，而是救的那個『人』。」這種人道主義的昂 揚，是人類文明一大進程。由於人道主義的出現，率獸食人的社會才絕跡於人間。由於人道 主義的覺醒，以人祭天的犧牲才消弭於人世。 根據上文，下列選項何者屬於人道主義的表現？', '["國際紅十字會對受害者提供保護及救助", "國際貨幣基金組織長期致力於穩定匯率", "無國界醫生在衝突地區提供醫療及物資", "世界展望會幫助貧困兒童以及進行賑災 歐洲聯盟促進社會經濟發展及公民覺醒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00484', 'elementary-f29af906', 'elementary-f29af906-moex-112-34c7f7f6', 'sub-elementary-f29af906-02', NULL, 'single_choice', '「知識分子既不是調解者，也不是建立共識的人，而是全身投注於批評意識，不願接受簡單 的處方、現成的陳腔濫調，或平和寬容的肯定權勢者的說法或作法。他總是時時維持著警覺 狀態，永遠不讓似是而非的事物或約定俗成的觀念牽著鼻子走。」 根據上文，下列選項何者符合知識分子的特質？', '["不落俗套", "左右逢源", "通才碩學", "韜光養晦 慎思明辨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00485', 'elementary-f29af906', 'elementary-f29af906-moex-112-34c7f7f6', 'sub-elementary-f29af906-02', NULL, 'single_choice', '「心理學的研究上有個現象叫做『破窗效應』，就是說，一個房子如果窗戶破了，沒有人去 修補，隔不久，其它的窗戶也會莫名其妙的被人打破；一面牆，如果出現一些塗鴉沒有清洗 掉，很快地，牆上就布滿了亂七八糟，不堪入目的東西。一個很乾淨的地方，人會不好意思 丟垃圾，但是一旦地上有垃圾出現之後，人就會毫不猶疑地拋，絲毫不覺羞愧。這真是很奇 怪的現象。」 根據上文，下列選項何者符合「破窗效應」的觀點？', '["管理時必須有統一的要求與準則", "防微杜漸是預防問題的手段之一", "人們很容易仿效他人不良的行為", "組織中引進競爭者可以激發活力 環境對人的行為具有強烈誘導性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00486', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法之規定，個人或團體所有土地面積之最高額限制，由該管直轄市或縣（市）政府規定辦法， 限令於一定期間內，將額外土地分劃出賣。不依前項規定分劃出賣者，該管直轄市或縣（市）政府 得依本法徵收之。前項徵收之補償地價，得斟酌情形搭給土地債券。前述規定之土地債券，其清付 期限，依土地法施行法規定，最長不得逾多少時間？', '["1年", "3年", "5年", "10年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00487', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '下列有關土地法規定之定義，何者錯誤？', '["本法所稱土地，謂水陸及天然富源", "本法所稱公有土地，為國有土地、直轄市有土地、縣（市）有土地或鄉（鎮、市、區）有之土地", "本法所稱自耕，係指自任耕作者而言，其為維持一家生活直接經營耕作者，以自耕論", "本法所稱土地債券，為土地銀行依法所發行之債券"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
